        team_room_obj.write({'order_id': record.id})
    if room_transition_obj:
        room_transition_obj.write({'order_id': record.id})

for order in records:
    order.appointment_id.write({'start_sync_to_i360': False})
    order.write({ 'is_data_upload_completed': True})

for order in records:
    if order.appointment_id:
        order.appointment_id.write({'start_sync_to_i360': False})
    order.write({'is_data_upload_completed': True})

for order in records:
    if order.appointment_id:
        order.appointment_id.write({'start_sync_to_i360': True})
    order.write({ 'is_data_upload_completed': False})

credit_application = model.env['team.credit.application'].search([('order_id', '=', record.id)], limit=1, order='id desc')
if credit_application:
    if credit_application.attachment_id:
        credit_application.attachment_id.write({'improveit_id': ''})
record.action_upload_credit_application({})

transaction_logs = record.card_transaction_log_line.filtered(lambda x: x.state == 'failed' and not x.synced)
if transaction_logs:
    transaction_logs.write({'synced': True})
